+# bun-workflow
+
+SQLite-first durable workflows for Bun.
+
+```ts
+import { createEvent, createRuntime, createWorkflow } from "bun-workflow";
+```
+
+## Install
+
+```bash
+bun add bun-workflow
+```
+
+## Core Model
+
+- Workflows are normal TypeScript functions.
+- Durable boundaries are explicit: `step.run()`, `step.sleep()`, `step.sleepUntil()`, and `step.waitForEvent()`.
+- Runs replay from the top after retries or recovery.
+- Completed durable steps reuse their checkpointed result.
+- One authoritative worker owns intake, cron, debounce, and execution for a SQLite database.
+
+Code outside a durable step may run more than once. External side effects inside a step should still use idempotency keys where possible.
+
+## Quick Start
+
+```ts
+import { createRuntime, createWorkflow } from "bun-workflow";
+
+export const syncAccount = createWorkflow<{
+  accountId: string;
+  source: "api" | "manual";
+}>(
+  {
+    id: "sync-account",
+    retries: {
+      attempts: 12,
+      minDelay: "1s",
+      maxDelay: "5m",
+      backoff: "exponential",
+    },
+  },
+  async ({ input, step }) => {
+    const account = await step.run("load-account", async () => {
+      return db.accounts.get(input.accountId);
+    });
+
+    await step.run("push-to-crm", async () => {
+      await crm.upsertAccount(account, {
+        idempotencyKey: `crm:${input.accountId}`,
+      });
+    });
+  },
+);
+
+export const runtime = createRuntime({
+  database: "sqlite://./.bun-workflow/bun-workflow.db",
+  workflows: [syncAccount],
+  events: [],
+});
+
+await runtime.startWorker({
+  workers: 4,
+});
+
+await runtime.run(syncAccount, {
+  accountId: "acc_123",
+  source: "manual",
+});
+```
+
+## Events
+
+```ts
+import { createEvent, createRuntime, createWorkflow } from "bun-workflow";
+
+const accountUpdated = createEvent<{
+  accountId: string;
+  reason?: string;
+}>({
+  name: "account.updated",
+});
+
+const reindexAccount = createWorkflow<{
+  accountId: string;
+  reason?: string;
+}>(
+  {
+    id: "reindex-account",
+    trigger: accountUpdated,
+    debounce: {
+      key: (input) => input.accountId,
+      period: "30s",
+      timeout: "10m",
+    },
+    concurrency: {
+      limit: 1,
+      key: (input) => input.accountId,
+    },
+  },
+  async ({ input, event, step }) => {
+    await step.run("rebuild-index", async () => {
+      await search.reindexAccount(input.accountId, {
+        reason: input.reason,
+        eventId: event?.id,
+      });
+    });
+  },
+);
+
+const runtime = createRuntime({
+  database: "sqlite://./.bun-workflow/bun-workflow.db",
+  workflows: [reindexAccount],
+  events: [accountUpdated],
+});
+
+await runtime.send(
+  accountUpdated,
+  {
+    accountId: "acc_123",
+    reason: "crm-import",
+  },
+  {
+    idempotencyKey: "account.updated:evt_123",
+  },
+);
+```
+
+## Wait For Events
+
+```ts
+import { createEvent, createWorkflow } from "bun-workflow";
+
+const shipmentPacked = createEvent<{
+  orderId: string;
+  trackingNumber: string;
+}>({
+  name: "shipment.packed",
+});
+
+export const fulfillOrder = createWorkflow<{
+  orderId: string;
+  email: string;
+}>(
+  {
+    id: "fulfill-order",
+  },
+  async ({ input, step }) => {
+    await step.run("reserve-inventory", async () => {
+      await warehouse.reserve(input.orderId);
+    });
+
+    const packed = await step.waitForEvent(shipmentPacked, {
+      key: input.orderId,
+      timeout: "7d",
+    });
+
+    await step.run("send-tracking-email", async () => {
+      await emails.sendTrackingEmail(input.email, packed.trackingNumber);
+    });
+  },
+);
+```
+
+## Sleep
+
+```ts
+const sendReminder = createWorkflow<{
+  subscriptionId: string;
+  remindAt: Date;
+}>(
+  {
+    id: "send-reminder",
+  },
+  async ({ input, step }) => {
+    await step.sleepUntil("wait-for-reminder", input.remindAt);
+
+    await step.run("send-email", async () => {
+      await emails.sendRenewalReminder(input.subscriptionId);
+    });
+  },
+);
+```
+
+## Cron
+
+```ts
+const nightlyCleanup = createWorkflow(
+  {
+    id: "nightly-cleanup",
+    trigger: {
+      cron: "0 3 * * *",
+      timezone: "Europe/Vienna",
+    },
+  },
+  async ({ step }) => {
+    const staleIds = await step.run("find-stale-sessions", async () => {
+      return db.sessions.findStaleIds();
+    });
+
+    await step.run("delete-stale-sessions", async () => {
+      await db.sessions.deleteMany(staleIds);
+    });
+  },
+);
+```
+
+Human-friendly cron helpers are exported from `bun-workflow/cron`:
+
+```ts
+import { describeCron, nextRuns } from "bun-workflow/cron";
+
+describeCron("0 3 * * *", { timezone: "Europe/Vienna" });
+nextRuns("0 3 * * *", { timezone: "Europe/Vienna", count: 3 });
+```
+
+## Standalone Worker Process
+
+Worker process:
+
+```ts
+const runtime = createRuntime({
+  database: "sqlite://./.bun-workflow/bun-workflow.db",
+  workflows: [syncAccount, reindexAccount, fulfillOrder],
+  events: [accountUpdated, shipmentPacked],
+  server: { port: 8787 },
+});
+
+await runtime.startWorker({
+  workers: 8,
+});
+```
+
+Remote client:
+
+```ts
+const runtime = createRuntime({
+  server: "http://127.0.0.1:8787",
+  workflows: [syncAccount, reindexAccount, fulfillOrder],
+  events: [accountUpdated, shipmentPacked],
+});
+
+await runtime.run(syncAccount, {
+  accountId: "acc_123",
+  source: "manual",
+});
+```
+
+## Inspection
+
+```ts
+const run = await runtime.run(syncAccount, {
+  accountId: "acc_123",
+  source: "manual",
+});
+
+await runtime.getRun(run.id);
+await runtime.listRuns();
+await runtime.inspectRun(run.id);
+await runtime.cancel(run.id);
+await runtime.replayRun(run.id);
+```
+
+## Scripts
+
